solution_code:
#include <iostream>
#include <string>

class Sensor
{
protected:
    int m_reading{};

public:
    Sensor(int reading)
        : m_reading{ reading }
    {
    }

    void printReading() const
    {
        std::cout << "Sensor reading: " << m_reading << '\n';
    }
};

class LabeledSensor : public Sensor
{
    std::string m_label{};

public:
    LabeledSensor(const std::string& label, int reading)
        : Sensor{ reading }, m_label{ label }
    {
    }

    void printLabeled() const
    {
        std::cout << m_label << ": " << m_reading
                  << " [" << (m_reading >= 0 ? "OK" : "WARN") << "]\n";
    }
};

int main()
{
    std::string label{};
    std::cin >> label;

    int reading{};
    std::cin >> reading;

    LabeledSensor ls{ label, reading };
    ls.printReading();
    ls.printLabeled();

    return 0;
}

